def quick_sort(arr):
    if len(arr) < 2:
        return arr

    pivot = arr[(len(arr)) // 2]
    less = [i for i in arr if i < pivot]
    equal = [elem for elem in arr if elem == pivot]
    greater = [i for i in arr if i > pivot]
    return quick_sort(less) + equal + quick_sort(greater)



arr = [5, 16, 2, 6, 3, 2, 8, 7, 10, 16]
print(quick_sort(arr))

def get_min_idx(arr):
    min_elem = arr[0]
    min_idx = 0
    for i in range(1, len(arr)):
        if arr[i] < min_elem:
            min_elem = arr[i]
            min_idx = i
    return min_idx


def choice_sort(arr):
    new_arr = []
    for i in range(len(arr)):
        min_elem = get_min_idx(arr)
        new_arr.append(arr.pop(min_elem))
    return new_arr



arr = [16, 5, 2, 6, 3, 2, 8, 7, 16, 10]
print(choice_sort(arr))

def bubble(arr):
    n = len(arr)

    for i in range(n):
        flag = False
        for j in range(n - i - 1):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
                flag = True
        if not flag:
            break
    return arr


arr = [5, 16, 2, 6, 3, 2, 8, 7, 10, 16]
print(bubble(arr))
